window.LIVRO_DATA = {
    nome: "Volume 8",
    dados: [
{
    termo: "<span class='numero-ordem'>701.</span> <span class='nome-principal'>Béquer</span> <span class='subtitulo'>– filho de Benjamim (Gn 46:21; 1Cr 7:6)</span>",
    definicao: "<p><strong>Béquer</strong> foi um dos filhos de Benjamim, neto de Jacó.</p><ul><li><strong>Nome:</strong> significa 'jovem camelo' ou 'primogênito'</li><li>Sua descendência, os bequeritas (<span class='versiculo'>Nm 26:35</span>), foi uma família da tribo de Benjamim</li><li>Representa os clãs que compunham a tribo de Benjamim</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 46:21; Nm 26:35; 1Cr 7:6</span>"
},
{
    termo: "<span class='numero-ordem'>702.</span> <span class='nome-principal'>Jediael</span> <span class='subtitulo'>– filho de Benjamim (1Cr 7:6,10-11)</span>",
    definicao: "<p><strong>Jediael</strong> foi outro filho de Benjamim, mencionado em <span class='versiculo'>1Cr 7:6,10-11</span>.</p><ul><li>Seus descendentes foram guerreiros valentes</li><li><strong>Nome:</strong> significa 'conhecido por Deus'</li><li>Representa a linhagem guerreira de Benjamim</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 7:6,10-11</span>"
},
{
    termo: "<span class='numero-ordem'>703.</span> <span class='nome-principal'>Belá (Bela)</span> <span class='subtitulo'>– filho de Benjamim, provavelmente o primogênito (Gn 46:21; Nm 26:38)</span>",
    definicao: "<p><strong>Belá</strong> foi filho de Benjamim, chefe da família dos belaítas.</p><ul><li><strong>Nome:</strong> significa 'engolir' ou 'destruição'</li><li>É o ancestral do rei Saul (<span class='versiculo'>1Sm 9:1</span>)</li><li>Representa a linhagem real de Benjamim</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 46:21; Nm 26:38; 1Cr 8:1-2</span>"
},
{
    termo: "<span class='numero-ordem'>704.</span> <span class='nome-principal'>Abiel</span> <span class='subtitulo'>– avô de Saul (1Sm 9:1)</span>",
    definicao: "<p><strong>Abiel</strong>, filho de Zeror, foi avô do rei Saul e de Abner (<span class='versiculo'>1Sm 9:1</span>; <span class='versiculo'>14:51</span>). Era benjamita, da família de Belá.</p><ul><li><strong>Nome:</strong> significa 'meu pai é Deus'</li><li>Representa a linhagem que produziu o primeiro rei de Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 9:1; 1Sm 14:51; 1Cr 8:30; 1Cr 9:36</span>"
},
{
    termo: "<span class='numero-ordem'>705.</span> <span class='nome-principal'>Ner</span> <span class='subtitulo'>– pai de Abner, tio de Saul (1Sm 14:50-51)</span>",
    definicao: "<p><strong>Ner</strong> era filho de Abiel, irmão de Quis (pai de Saul). Portanto, Abner era primo de Saul.</p><ul><li><strong>Nome:</strong> significa 'lâmpada' ou 'vela'</li><li>Representa a família nobre de Benjamim antes da monarquia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 14:50-51; 1Cr 8:33; 1Cr 9:39</span>"
},
{
    termo: "<span class='numero-ordem'>706.</span> <span class='nome-principal'>Quis</span> <span class='subtitulo'>– pai de Saul, benjamita (1Sm 9:1-2)</span>",
    definicao: "<p><strong>Quis</strong>, filho de Abiel, foi pai do rei Saul. Era um homem poderoso e rico.</p><ul><li><strong>Nome:</strong> significa 'armadilha' ou 'arco'</li><li>Representa a linhagem que deu origem ao primeiro rei, mas também à instabilidade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 9:1-2; 1Sm 14:51; At 13:21</span>"
},
{
    termo: "<span class='numero-ordem'>707.</span> <span class='nome-principal'>Zeror</span> <span class='subtitulo'>– avô de Ner (1Sm 9:1)</span>",
    definicao: "<p><strong>Zeror</strong>, filho de Becorate, filho de Afia, da tribo de Benjamim. É ancestral de Saul.</p><ul><li><strong>Nome:</strong> significa 'pacote' ou 'feixe'</li><li>Representa a genealogia pouco conhecida de Saul</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 9:1</span>"
},
{
    termo: "<span class='numero-ordem'>708.</span> <span class='nome-principal'>Afi a</span> <span class='subtitulo'>– benjamita, ancestral de Saul (1Sm 9:1)</span>",
    definicao: "<p><strong>Afi a</strong> (ou Afia) é mencionado como antepassado de Quis.</p><ul><li><strong>Nome:</strong> significa 'soprar' ou 'cansado'</li><li>É uma figura obscura, mas essencial na genealogia de Saul</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 9:1</span>"
},
{
    termo: "<span class='numero-ordem'>709.</span> <span class='nome-principal'>Becorate</span> <span class='subtitulo'>– outro ancestral de Saul (1Sm 9:1)</span>",
    definicao: "<p><strong>Becorate</strong>, filho de Zeror, neto de Afia.</p><ul><li><strong>Nome:</strong> significa 'primogênito' ou 'bênção'</li><li>Completa a genealogia de Saul até Belá, filho de Benjamim</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 9:1</span>"
},
{
    termo: "<span class='numero-ordem'>710.</span> <span class='nome-principal'>Ainoã</span> <span class='subtitulo'>– esposa de Saul, mãe de Merabe e Mical (1Sm 14:50)</span>",
    definicao: "<p><strong>Ainoã</strong>, filha de Aimaás, foi esposa do rei Saul (<span class='versiculo'>1Sm 14:50</span>).</p><ul><li><strong>Nome:</strong> significa 'irmã da graça' ou 'olho da graça'</li><li>Teve Merabe e Mical</li><li>Representa as rainhas-mães do período de Saul</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 14:50</span>"
},
{
    termo: "<span class='numero-ordem'>711.</span> <span class='nome-principal'>Isbosete</span> <span class='subtitulo'>– filho de Saul, rei de Israel por um tempo (2Sm 2:8-15)</span>",
    definicao: "<p><strong>Isbosete</strong> (também chamado Esbaal) foi filho de Saul, proclamado rei de Israel por Abner após a morte de Saul. Reinou por dois anos, mas foi assassinado por Recabe e Baaná (<span class='versiculo'>2Sm 4:5-12</span>).</p><ul><li><strong>Nome:</strong> significa 'homem de vergonha' (originalmente Esbaal – 'homem de Baal')</li><li>Representa a resistência da casa de Saul contra Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 2:8-15; 2Sm 3:6-11; 2Sm 4:5-12; 1Cr 8:33; 1Cr 9:39</span>"
},
{
    termo: "<span class='numero-ordem'>712.</span> <span class='nome-principal'>Mica</span> <span class='subtitulo'>– filho de Mefibosete, neto de Jônatas (1Cr 8:34-35; 2Sm 9:12)</span>",
    definicao: "<p><strong>Mica</strong>, filho de Mefibosete (neto de Jônatas), continuou a linhagem de Saul. Teve quatro filhos (Pitom, Meleque, Tareia e Acaz).</p><ul><li><strong>Nome:</strong> significa 'humilde' ou 'quem é como Yahweh?'</li><li>Representa a descendência de Jônatas que foi poupada por Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 9:12; 1Cr 8:34-35</span>"
},
{
    termo: "<span class='numero-ordem'>713.</span> <span class='nome-principal'>Recabe e Baaná</span> <span class='subtitulo'>– assassinos de Isbosete, executados por Davi (2Sm 4:2-12)</span>",
    definicao: "<p><strong>Recabe e Baaná</strong>, filhos de Rimom, de Beerote, eram capitães de tropas de Isbosete. Mataram Isbosete em sua cama, cortaram sua cabeça e a levaram a Davi, esperando recompensa. Davi, porém, os executou.</p><ul><li><strong>Nomes:</strong> Recabe ('cavaleiro' ou 'carruagem'); Baaná ('em angústia')</li><li>Representam a traição que não é recompensada pelo rei ungido</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 4:2-12</span>"
},
{
    termo: "<span class='numero-ordem'>714.</span> <span class='nome-principal'>Merabe</span> <span class='subtitulo'>– filha de Saul, esposa de Adriel (2Sm 21:8)</span>",
    definicao: "<p><strong>Merabe</strong>, filha de Saul, casou-se com Adriel. Teve cinco filhos que foram entregues aos gibeonitas para expiar o pecado de Saul. Foram executados.</p><ul><li>Seus nomes não são dados</li><li>Representam as consequências do pecado de Saul</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 21:8</span>"
},
{
    termo: "<span class='numero-ordem'>715.</span> <span class='nome-principal'>Armoni e Mefibosete (filhos de Saul com Rizpa)</span> <span class='subtitulo'>– executados pelos gibeonitas (2Sm 21:8-9)</span>",
    definicao: "<p><strong>Armoni e Mefibosete</strong> foram filhos de Saul com Rizpa, entregues aos gibeonitas para execução, juntamente com os cinco filhos de Merabe.</p><ul><li>Armoni significa 'príncipe' ou 'do palácio'</li><li>Mefibosete aqui é outro, não o filho de Jônatas</li><li>Representam o preço do pecado de Saul</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 21:8-9</span>"
},
{
    termo: "<span class='numero-ordem'>716.</span> <span class='nome-principal'>Itai, o geteu</span> <span class='subtitulo'>– comandante filisteu leal a Davi (2Sm 15:19-22)</span>",
    definicao: "<p><strong>Itai</strong>, natural de Gate (filisteu), era comandante de 600 homens que se juntaram a Davi quando ele fugia de Absalão. Davi quis poupá-lo, mas Itai jurou lealdade: <span class='destaque-amarelo'>'Viva o rei, onde quer que esteja, ali estará teu servo'</span> (<span class='versiculo'>2Sm 15:18-22</span>).</p><ul><li><strong>Nome:</strong> significa 'comigo está Deus'</li><li>Itai é exemplo de lealdade estrangeira</li><li>É provavelmente um prosélito</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 15:19-22; 2Sm 18:2,5,12</span>"
},
{
    termo: "<span class='numero-ordem'>717.</span> <span class='nome-principal'>Sobeque</span> <span class='subtitulo'>– guerreiro de Davi que matou Saf, um gigante (2Sm 21:18)</span>",
    definicao: "<p><strong>Sobeque</strong>, um dos trinta guerreiros de Davi (<span class='versiculo'>2Sm 21:18</span>; <span class='versiculo'>1Cr 11:29</span>; <span class='versiculo'>20:4</span>). Matou Saf, um descendente dos gigantes (refains) na batalha contra os filisteus.</p><ul><li><strong>Nome:</strong> significa 'ramificado' ou 'tecelão'</li><li>Também chamado Sibecai</li><li>Foi chefe do oitavo turno mensal (<span class='versiculo'>1Cr 27:11</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 21:18; 1Cr 11:29; 1Cr 20:4; 1Cr 27:11</span>"
},
{
    termo: "<span class='numero-ordem'>718.</span> <span class='nome-principal'>Hirão (Hiram)</span> <span class='subtitulo'>– rei de Tiro, aliado de Davi e Salomão (2Sm 5:11; 1Rs 5)</span>",
    definicao: "<p><strong>Hirão</strong> foi rei de Tiro (c. 980-947 a.C.). Enviou madeira de cedro e artesãos a Davi para construir seu palácio (<span class='versiculo'>2Sm 5:11</span>). Forneceu madeira e ouro para Salomão construir o templo (<span class='versiculo'>1Rs 5</span>).</p><ul><li><strong>Nome:</strong> significa 'irmão exaltado' ou 'nobre'</li><li>Hirão reconheceu o Deus de Israel (<span class='versiculo'>1Rs 5:7</span>)</li><li>Representa a cooperação entre os povos para a obra de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 5:11; 1Rs 5:1-12; 1Rs 7:13-14; 1Rs 9:10-14; 2Cr 2:3-16</span>"
},
{
    termo: "<span class='numero-ordem'>719.</span> <span class='nome-principal'>Rainha de Sabá</span> <span class='subtitulo'>– soberana que visitou Salomão (1Rs 10:1-13)</span>",
    definicao: "<p>A <strong>Rainha de Sabá</strong> governava o reino de Sabá (possivelmente no Iêmen ou Etiópia). Ouviu a fama da sabedoria de Salomão e veio a Jerusalém com grande comitiva, trazendo especiarias, ouro e pedras preciosas. Provou Salomão com perguntas difíceis, e ele respondeu todas. Ela declarou: <span class='destaque-amarelo'>'Bendito seja o teu Deus'</span> (<span class='versiculo'>1Rs 10:1-13</span>; <span class='versiculo'>2Cr 9:1-12</span>).</p><ul><li>Seu nome não é dado; 'Rainha de Sabá' é título</li><li>Jesus se referiu a ela como 'rainha do Sul' (<span class='versiculo'>Mt 12:42</span>; <span class='versiculo'>Lc 11:31</span>)</li><li>Representa os gentios que reconhecem a sabedoria de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 10:1-13; 2Cr 9:1-12; Mt 12:42; Lc 11:31</span>"
},
{
    termo: "<span class='numero-ordem'>720.</span> <span class='nome-principal'>Nabal</span> <span class='subtitulo'>– rico insensato, marido de Abigail, morto por Deus (1Sm 25)</span>",
    definicao: "<p><strong>Nabal</strong> era natural de Carmelo (Judá), descendente de Calebe. Era rico, mas grosseiro e mau. Recusou ajudar Davi e seus homens. Davi preparou-se para matá-lo, mas Abigail o impediu. <span class='destaque-vermelho'>Dez dias depois, Deus feriu Nabal, e ele morreu</span> (<span class='versiculo'>1Sm 25:1-38</span>).</p><ul><li><strong>Nome:</strong> significa 'tolo' ou 'insensato'</li><li>Abigail tornou-se esposa de Davi</li><li>Nabal é mencionado apenas em <span class='versiculo'>1Sm 25</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 25:1-38</span>"
},
{
    termo: "<span class='numero-ordem'>721.</span> <span class='nome-principal'>Bigtã e Teres</span> <span class='subtitulo'>– eunucos que conspiraram contra o rei Assuero (Et 2:21-23)</span>",
    definicao: "<p><strong>Bigtã e Teres</strong> eram dois oficiais persas, guardas da porta do palácio, que planejaram assassinar o rei Assuero. Mardoqueu descobriu a trama e avisou a rainha Ester. Os conspiradores foram enforcados (<span class='versiculo'>Et 2:21-23</span>).</p><ul><li>Seus nomes são persas</li><li>Representam os inimigos que Deus frustra</li><li>Sua execução serviu para exaltar Mardoqueu</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Et 2:21-23; Et 6:1-2</span>"
},
{
    termo: "<span class='numero-ordem'>722.</span> <span class='nome-principal'>Zeresh</span> <span class='subtitulo'>– esposa de Hamã, conselheira maligna (Et 5:10-14; 6:13)</span>",
    definicao: "<p><strong>Zeresh</strong> era esposa de Hamã, o inimigo dos judeus. Aconselhou Hamã a construir uma forca para Mardoqueu (<span class='versiculo'>Et 5:14</span>). Depois, quando Hamã foi humilhado, Zeresh profetizou sua ruína (<span class='versiculo'>Et 6:13</span>).</p><ul><li><strong>Nome:</strong> significa 'estrangeira' ou 'dourada'</li><li>Zeresh representa aqueles que apoiam o mal, mas acabam destruídos</li><li>É um aviso contra a cumplicidade no pecado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Et 5:10-14; Et 6:13</span>"
},
{
    termo: "<span class='numero-ordem'>723.</span> <span class='nome-principal'>Candace (eunuco etíope)</span> <span class='subtitulo'>– rainha da Etiópia, cujo tesoureiro foi batizado por Filipe (At 8:26-40)</span>",
    definicao: "<p><strong>Candace</strong> é o título das rainhas da Etiópia (Meroé). O eunuco etíope, tesoureiro de Candace, estava em Jerusalém para adoração e, voltando, lia <span class='versiculo'>Is 53</span>. Filipe, guiado pelo Espírito, explicou-lhe as Escrituras e o batizou (<span class='versiculo'>At 8:26-40</span>).</p><ul><li>Candace significa 'rainha-mãe' (título)</li><li>O eunuco é um dos primeiros gentios convertidos</li><li>Representa as nações africanas alcançadas pelo evangelho</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 8:26-40</span>"
},
{
    termo: "<span class='numero-ordem'>724.</span> <span class='nome-principal'>Rode</span> <span class='subtitulo'>– serva na casa de Maria, mãe de João Marcos (At 12:13-16)</span>",
    definicao: "<p><strong>Rode</strong> era serva na casa de Maria, mãe de João Marcos (<span class='versiculo'>At 12:13</span>). Quando Pedro foi libertado da prisão, foi à casa onde muitos oravam. Rode reconheceu a voz de Pedro, mas de tanta alegria esqueceu de abrir a porta e correu para anunciar.</p><ul><li><strong>Nome:</strong> significa 'rosa' (grego)</li><li>Rode representa os servos fiéis que, mesmo pequenos, são instrumentos de Deus</li><li>Sua alegria é comovente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 12:13-16</span>"
},
{
    termo: "<span class='numero-ordem'>725.</span> <span class='nome-principal'>Os sete diáconos: Prócoro, Nicanor, Timão, Parmenas, Nicolau</span> <span class='subtitulo'>– servos escolhidos para servir às mesas (At 6:5)</span>",
    definicao: "<p><strong>Os sete diáconos</strong> – além de Estêvão e Filipe – foram escolhidos para servir às mesas (<span class='versiculo'>At 6:5</span>).</p><ul><li>Prócoro ('líder do coro'), Nicanor ('vitorioso'), Timão ('honrado'), Parmenas ('constante'), Nicolau ('vitorioso sobre o povo')</li><li>A tradição diz que todos foram martirizados</li><li>Nicolau é identificado por alguns com a seita dos nicolaítas (<span class='versiculo'>Ap 2:6,15</span>), mas não há prova</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 6:5</span>"
},
{
    termo: "<span class='numero-ordem'>726.</span> <span class='nome-principal'>Ninfas</span> <span class='subtitulo'>– cristã em Laodiceia que tinha igreja em casa (Cl 4:15)</span>",
    definicao: "<p><strong>Ninfas</strong> é mencionada em <span class='versiculo'>Cl 4:15</span>: 'Saudai os irmãos que estão em Laodiceia, e a Ninfa, e à igreja que está em sua casa'.</p><ul><li><strong>Nome:</strong> significa 'noiva' (grego)</li><li>Ninfas é exemplo de mulher que hospedava a igreja em sua casa</li><li>Representa as líderes femininas que abriam suas casas para o culto</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Cl 4:15</span>"
},
{
    termo: "<span class='numero-ordem'>727.</span> <span class='nome-principal'>Tíquico</span> <span class='subtitulo'>– companheiro de Paulo, mensageiro e portador de cartas (Ef 6:21; Cl 4:7)</span>",
    definicao: "<p><strong>Tíquico</strong> era natural da Ásia, cooperador de Paulo. Levou as cartas aos Efésios (<span class='versiculo'>Ef 6:21</span>), aos Colossenses (<span class='versiculo'>Cl 4:7</span>) e também acompanhou Paulo a Jerusalém (<span class='versiculo'>At 20:4</span>).</p><ul><li><strong>Nome:</strong> significa 'afortunado'</li><li>Tíquico é modelo de mensageiro fiel</li><li>A tradição diz que tornou-se bispo de Calcedônia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 20:4; Ef 6:21-22; Cl 4:7-8; 2Tm 4:12; Tt 3:12</span>"
},
{
    termo: "<span class='numero-ordem'>728.</span> <span class='nome-principal'>Aristarco</span> <span class='subtitulo'>– macedônio de Tessalônica, companheiro de Paulo na prisão (At 19:29; 27:2; Cl 4:10)</span>",
    definicao: "<p><strong>Aristarco</strong> era natural de Tessalônica, acompanhou Paulo em várias viagens. Foi arrastado pela multidão em Éfeso (<span class='versiculo'>At 19:29</span>). Esteve com Paulo na Grécia e na Ásia (<span class='versiculo'>At 20:4</span>). Foi para Roma com Paulo (<span class='versiculo'>At 27:2</span>) e é chamado de <span class='destaque-amarelo'>'companheiro de prisão'</span> (<span class='versiculo'>Cl 4:10</span>).</p><ul><li><strong>Nome:</strong> significa 'melhor governante'</li><li>Aristarco representa os que sofrem com os líderes</li><li>A tradição diz que foi martirizado sob Nero</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 19:29; At 20:4; At 27:2; Cl 4:10; Fm 24</span>"
},
{
    termo: "<span class='numero-ordem'>729.</span> <span class='nome-principal'>Justo (Jesus Justo)</span> <span class='subtitulo'>– cristão judeu, saudado por Paulo (Cl 4:11)</span>",
    definicao: "<p><strong>Justo</strong> é mencionado em <span class='versiculo'>Cl 4:11</span> como 'Jesus, chamado Justo', um dos cooperadores de Paulo que eram da circuncisão.</p><ul><li><strong>Nome:</strong> significa 'justo' (nome romano)</li><li>Representa muitos cristãos judeus anônimos</li><li>Esteve com Paulo na prisão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Cl 4:11</span>"
},
{
    termo: "<span class='numero-ordem'>730.</span> <span class='nome-principal'>Demas</span> <span class='subtitulo'>– cooperador de Paulo que o abandonou por amor ao mundo (2Tm 4:10)</span>",
    definicao: "<p><strong>Demas</strong> é mencionado em <span class='versiculo'>Fm 24</span> e <span class='versiculo'>Cl 4:14</span> como cooperador de Paulo. Na segunda carta a Timóteo, Paulo escreve: <span class='destaque-vermelho'>'Demas me abandonou, tendo amado o presente século, e foi para Tessalônica'</span> (<span class='versiculo'>2Tm 4:10</span>).</p><ul><li><strong>Nome:</strong> significa 'popular' ou 'governante do povo'</li><li>Demas é um aviso contra o amor ao mundo</li><li>Ele abandonou Paulo na prisão, quando o apóstolo mais precisava</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Cl 4:14; Fm 24; 2Tm 4:10</span>"
},
{
    termo: "<span class='numero-ordem'>731.</span> <span class='nome-principal'>Pudente, Lino e Cláudia</span> <span class='subtitulo'>– cristãos romanos saudados por Paulo (2Tm 4:21)</span>",
    definicao: "<p><strong>Pudente, Lino e Cláudia</strong> são mencionados em <span class='versiculo'>2Tm 4:21</span>: 'Saúdam-te Pudente, Lino, Cláudia e todos os irmãos'.</p><ul><li><strong>Nomes:</strong> Pudente ('modesto'); Lino (nome romano); Cláudia (feminino)</li><li>A tradição diz que Lino tornou-se bispo de Roma</li><li>Cláudia pode ser a esposa de Pudente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Tm 4:21</span>"
},
{
    termo: "<span class='numero-ordem'>732.</span> <span class='nome-principal'>Gaio (3 João)</span> <span class='subtitulo'>– hospitaleiro, a quem João escreveu (3Jo 1-8)</span>",
    definicao: "<p><strong>Gaio</strong> é o destinatário da terceira epístola de João. João o elogia por sua fidelidade e hospitalidade aos irmãos missionários.</p><ul><li><strong>Nome:</strong> significa 'senhor' (grego)</li><li>Gaio é exemplo de amor e hospitalidade</li><li>Há vários Gaios no NT: Gaio de Corinto (<span class='versiculo'>1Co 1:14</span>), Gaio de Derbe (<span class='versiculo'>At 20:4</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>3Jo 1-8; Rm 16:23; 1Co 1:14; At 19:29; At 20:4</span>"
},
{
    termo: "<span class='numero-ordem'>733.</span> <span class='nome-principal'>A senhora eleita e seus filhos (2 João)</span> <span class='subtitulo'>– destinatária da segunda epístola de João (2Jo 1-13)</span>",
    definicao: "<p>A <strong>senhora eleita</strong> é a destinatária da segunda epístola de João (<span class='versiculo'>2Jo 1</span>). Pode ser uma figura real (uma mulher cristã) ou uma igreja (simbolicamente 'senhora').</p><ul><li>É elogiada por seus filhos andarem na verdade</li><li>João adverte contra falsos mestres</li><li>Ela representa a fidelidade doutrinária</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Jo 1-13</span>"
},
{
    termo: "<span class='numero-ordem'>734.</span> <span class='nome-principal'>Os 24 anciãos do Apocalipse</span> <span class='subtitulo'>– seres celestiais que adoram a Deus (Ap 4-5)</span>",
    definicao: "<p>No Apocalipse 4-5, João vê <strong>24 tronos e 24 anciãos</strong> vestidos de branco, com coroas de ouro. Eles se prostram diante de Deus e cantam louvores.</p><ul><li>Representam a igreja glorificada (12 patriarcas + 12 apóstolos)</li><li>Oferecem as orações dos santos</li><li>Lançam suas coroas diante do trono</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 4:4,10; Ap 5:6-14; Ap 11:16; Ap 19:4</span>"
},
{
    termo: "<span class='numero-ordem'>735.</span> <span class='nome-principal'>As quatro criaturas viventes</span> <span class='subtitulo'>– querubins ou serafins no Apocalipse (Ap 4:6-9)</span>",
    definicao: "<p>As <strong>quatro criaturas viventes</strong> são descritas em Apocalipse 4:6-9. São quatro seres cheios de olhos, com seis asas. Cada um tem uma face: leão, boi, homem, águia. Cantam <span class='destaque-amarelo'>'Santo, Santo, Santo'</span> dia e noite.</p><ul><li>Representam a criação e os atributos de Deus</li><li>São símbolos dos quatro evangelistas</li><li>Não descansam (<span class='versiculo'>Ap 4:8</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 4:6-9; Ap 5:6-14; Ap 6:1-7; Ap 15:7; Ap 19:4</span>"
},
{
    termo: "<span class='numero-ordem'>736.</span> <span class='nome-principal'>A mulher vestida de sol</span> <span class='subtitulo'>– figura simbólica do Apocalipse (Israel e/ou Maria) (Ap 12:1-6)</span>",
    definicao: "<p>A <strong>mulher vestida de sol</strong> aparece em Apocalipse 12:1-2: uma mulher vestida de sol, com a lua debaixo dos pés e uma coroa de 12 estrelas. Ela está grávida e clama com dores de parto.</p><ul><li>É interpretada como Israel (que deu à luz o Messias) ou como a igreja</li><li>Ela é perseguida pelo dragão (Satanás)</li><li>As 12 estrelas representam as 12 tribos de Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 12:1-6,13-17</span>"
},
{
    termo: "<span class='numero-ordem'>737.</span> <span class='nome-principal'>A besta do mar</span> <span class='subtitulo'>– poder político anticristão (Ap 13:1-10)</span>",
    definicao: "<p>A <strong>besta do mar</strong> aparece em Apocalipse 13:1-10: uma besta que emerge do mar, com dez chifres e sete cabeças, semelhante a um leopardo. Recebe poder do dragão. É o poder do Anticristo.</p><ul><li>O número 666 é o número da besta (<span class='versiculo'>Ap 13:18</span>)</li><li>A besta blasfema contra Deus e faz guerra aos santos</li><li>Será derrotada por Cristo (<span class='versiculo'>Ap 19:20</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 11:7; Ap 13:1-10; Ap 17:3; Ap 19:20; Ap 20:10</span>"
},
{
    termo: "<span class='numero-ordem'>738.</span> <span class='nome-principal'>A besta da terra (falso profeta)</span> <span class='subtitulo'>– poder religioso que apoia a besta (Ap 13:11-18)</span>",
    definicao: "<p>A <strong>besta da terra</strong> é a segunda besta em Apocalipse 13:11-18, que emerge da terra. Tem dois chifres como cordeiro, mas fala como dragão. Exerce a autoridade da primeira besta e obriga todos a adorar a imagem da besta.</p><ul><li>É o <span class='destaque-vermelho'>falso profeta</span> (<span class='versiculo'>Ap 19:20</span>)</li><li>Realiza sinais e coloca a marca da besta</li><li>Será lançado no lago de fogo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 13:11-18; Ap 16:13; Ap 19:20; Ap 20:10</span>"
},
{
    termo: "<span class='numero-ordem'>739.</span> <span class='nome-principal'>Babilônia (a grande prostituta)</span> <span class='subtitulo'>– cidade-símbolo da corrupção mundial (Ap 17-18)</span>",
    definicao: "<p><strong>Babilônia, a grande prostituta</strong>, aparece em Apocalipse 17-18: uma mulher sentada sobre uma besta, vestida de púrpura e escarlate. É a grande cidade que reina sobre os reis da terra. Embriagada com o sangue dos santos. Será destruída por Deus.</p><ul><li>Representa o sistema mundial de opressão, riqueza e idolatria</li><li>Seu nome é mistério (<span class='versiculo'>Ap 17:5</span>)</li><li>Os crentes são chamados a sair dela (<span class='versiculo'>Ap 18:4</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 14:8; Ap 16:19; Ap 17:1-18; Ap 18:1-24</span>"
},
{
    termo: "<span class='numero-ordem'>740.</span> <span class='nome-principal'>As duas testemunhas</span> <span class='subtitulo'>– profetas que testemunharão nos últimos dias (Ap 11:3-12)</span>",
    definicao: "<p>As <strong>duas testemunhas</strong> em Apocalipse 11:3-12 profetizam por 1260 dias, vestidas de saco. Têm poder para fechar o céu, transformar água em sangue e ferir a terra. São mortas pela besta, mas <span class='destaque-amarelo'>ressuscitam após três dias e meio</span> e sobem ao céu.</p><ul><li>Geralmente identificadas como Moisés e Elias (ou Enoque e Elias)</li><li>Representam o testemunho fiel em meio à perseguição</li><li>São as duas oliveiras e dois candeeiros (<span class='versiculo'>Zc 4</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 11:3-12</span>"
},
{
    termo: "<span class='numero-ordem'>741.</span> <span class='nome-principal'>Nereu e sua irmã</span> <span class='subtitulo'>– cristãos romanos saudados por Paulo (Rm 16:15)</span>",
    definicao: "<p><strong>Nereu e sua irmã</strong> são mencionados em <span class='versiculo'>Rm 16:15</span>: 'Saudai Filólogo e Júlia, Nereu e sua irmã, Olimpas e todos os santos que estão com eles'.</p><ul><li><strong>Nome:</strong> significa 'do mar' (deus marinho grego)</li><li>Nereu representa os muitos cristãos anônimos</li><li>A tradição diz que Nereu foi martirizado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:15</span>"
},
{
    termo: "<span class='numero-ordem'>742.</span> <span class='nome-principal'>Filólogo e Júlia</span> <span class='subtitulo'>– casal ou irmãos na igreja romana (Rm 16:15)</span>",
    definicao: "<p><strong>Filólogo e Júlia</strong> são mencionados em <span class='versiculo'>Rm 16:15</span> como parte do grupo de Nereu.</p><ul><li>Filólogo significa 'amante das palavras'; Júlia é nome romano feminino</li><li>São exemplo de casal cristão</li><li>Filólogo é um nome comum entre libertos imperiais</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:15</span>"
},
{
    termo: "<span class='numero-ordem'>743.</span> <span class='nome-principal'>Ampliato, Urbano, Estáquis, Apeles, Aristóbulo, Herodião, Narciso</span> <span class='subtitulo'>– cristãos romanos saudados por Paulo (Rm 16:8-11)</span>",
    definicao: "<p>Lista em <span class='versiculo'>Rm 16:8-11</span>: <strong>Ampliato</strong> (amado em Cristo), <strong>Urbano</strong> (nosso cooperador), <strong>Estáquis</strong> (amado), <strong>Apeles</strong> (aprovado em Cristo), <strong>Aristóbulo</strong>, <strong>Herodião</strong> (meu parente), <strong>Narciso</strong>.</p><ul><li>São nomes comuns entre escravos e libertos</li><li>Representam a diversidade da igreja romana</li><li>Paulo os saúda individualmente, mostrando seu cuidado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:8-11</span>"
},
{
    termo: "<span class='numero-ordem'>744.</span> <span class='nome-principal'>Trifena, Trifosa, Pérside</span> <span class='subtitulo'>– mulheres que trabalhavam no Senhor (Rm 16:12)</span>",
    definicao: "<p><strong>Trifena, Trifosa e Pérside</strong> são mencionadas em <span class='versiculo'>Rm 16:12</span>. Paulo as elogia por seu labor.</p><ul><li>Trifena e Trifosa são irmãs ou amigas (nomes gregos)</li><li>Pérside indica origem persa</li><li>Representam o ministério feminino ativo na igreja primitiva</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:12</span>"
},
{
    termo: "<span class='numero-ordem'>745.</span> <span class='nome-principal'>Rufo e sua mãe</span> <span class='subtitulo'>– cristãos romanos, filho de Simão Cireneu? (Rm 16:13)</span>",
    definicao: "<p><strong>Rufo e sua mãe</strong> são mencionados em <span class='versiculo'>Rm 16:13</span>: 'Saudai a Rufo, eleito no Senhor, e a sua mãe e minha'.</p><ul><li>A tradição o identifica com o filho de Simão Cireneu (<span class='versiculo'>Mc 15:21</span>)</li><li>Paulo chama sua mãe de 'minha mãe' (mãe espiritual)</li><li>Rufo representa os que foram alcançados pelo evangelho na casa de Simão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:13; Mc 15:21</span>"
},
{
    termo: "<span class='numero-ordem'>746.</span> <span class='nome-principal'>Asíncrito, Flegonte, Hermes, Pátrobas, Hermas</span> <span class='subtitulo'>– cristãos romanos (Rm 16:14)</span>",
    definicao: "<p><strong>Asíncrito, Flegonte, Hermes, Pátrobas, Hermas</strong> são mencionados em <span class='versiculo'>Rm 16:14</span> como um grupo.</p><ul><li>Asíncrito ('incomparável'), Flegonte ('ardente'), Hermes ('mensageiro'), Pátrobas ('patrício?'), Hermas (nome comum)</li><li>Representam a diversidade da igreja romana</li><li>Hermas é tradicionalmente identificado com o autor do Pastor de Hermas (apócrifo)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:14</span>"
},
{
    termo: "<span class='numero-ordem'>747.</span> <span class='nome-principal'>Olimpas</span> <span class='subtitulo'>– cristão em Romanos 16 (Rm 16:15)</span>",
    definicao: "<p><strong>Olimpas</strong> é mencionado em <span class='versiculo'>Rm 16:15</span> juntamente com Filólogo, Júlia, Nereu e sua irmã.</p><ul><li>Olimpas significa 'do Olimpo' (nome grego)</li><li>É exemplo de cristão comum</li><li>Pode ser um homem ou mulher (forma feminina Olimpa)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Rm 16:15</span>"
},
{
    termo: "<span class='numero-ordem'>748.</span> <span class='nome-principal'>Geazi</span> <span class='subtitulo'>– servo de Eliseu, amaldiçoado com lepra por cobiça (2Rs 5:20-27)</span>",
    definicao: "<p><strong>Geazi</strong> era servo do profeta Eliseu. Testemunhou a cura de Naamã. Quando Eliseu recusou o presente de Naamã, Geazi correu atrás dele e mentiu. Eliseu o confrontou e declarou: <span class='destaque-vermelho'>'A lepra de Naamã se pegará a ti e à tua descendência para sempre'</span> (<span class='versiculo'>2Rs 5:20-27</span>).</p><ul><li><strong>Nome:</strong> significa 'vale do repouso' (ironia)</li><li>Geazi é aviso contra a cobiça no ministério</li><li>Ele perdeu sua posição e saúde</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 4:27; 2Rs 5:20-27; 2Rs 8:4-6</span>"
},
{
    termo: "<span class='numero-ordem'>749.</span> <span class='nome-principal'>Dario (o medo)</span> <span class='subtitulo'>– rei que lançou Daniel na cova dos leões (Dn 5-6)</span>",
    definicao: "<p><strong>Dario</strong> foi rei da Babilônia (ou da Pérsia) após Belsazar (<span class='versiculo'>Dn 5:31</span>). Estabeleceu 120 sátrapas e três presidentes, incluindo Daniel. Lançou Daniel na cova dos leões, mas na manhã seguinte encontrou Daniel vivo e louvou o Deus de Daniel (<span class='versiculo'>Dn 6:1-28</span>).</p><ul><li><strong>Nome:</strong> significa 'possuidor do bem' (nome persa)</li><li>Dario representa o poder terreno que é forçado a reconhecer o Deus verdadeiro</li><li>É mencionado em <span class='versiculo'>Dn 5-6</span> e <span class='versiculo'>9:1</span>; <span class='versiculo'>11:1</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Dn 5:31; Dn 6:1-28; Dn 9:1; Dn 11:1</span>"
},
{
    termo: "<span class='numero-ordem'>750.</span> <span class='nome-principal'>Beltessazar</span> <span class='subtitulo'>– nome babilônico de Daniel, chefe dos magos (Dn 1:7; 4:9)</span>",
    definicao: "<p><strong>Beltessazar</strong> é o nome dado a Daniel pelo chefe dos eunucos na Babilônia (<span class='versiculo'>Dn 1:7</span>). Beltessazar significa 'protege a sua vida' (referência a Bel).</p><ul><li>Não confundir com Belsazar, o rei</li><li>Daniel tornou-se chefe dos sábios (<span class='versiculo'>Dn 4:9</span>; <span class='versiculo'>5:11</span>)</li><li>Beltessazar representa a fidelidade em meio à cultura pagã</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Dn 1:7; Dn 2:26; Dn 4:8-9; Dn 5:12</span>"
},
{
    termo: "<span class='numero-ordem'>751.</span> <span class='nome-principal'>Issacar</span> <span class='subtitulo'>– nono filho de Jacó, quinto de Lia (Gn 30:17-18)</span>",
    definicao: "<p><strong>Issacar</strong> foi filho de Jacó e Lia, nascido após Zebulom (<span class='versiculo'>Gn 30:17-18</span>). Lia disse: 'Deus me deu o meu galardão'.</p><ul><li><strong>Nome:</strong> significa 'galardão' ou 'há recompensa'</li><li>A tribo de Issacar era conhecida por seu conhecimento dos tempos (<span class='versiculo'>1Cr 12:32</span>)</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:14-15</span>) o descreve como jumento forte</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:17-18; Gn 35:23; Gn 46:13; Gn 49:14-15; Êx 1:3; Nm 1:28-29; Dt 33:18-19; Js 19:17-23; 1Cr 12:32</span>"
},
{
    termo: "<span class='numero-ordem'>752.</span> <span class='nome-principal'>Zebulom</span> <span class='subtitulo'>– décimo filho de Jacó, sexto de Lia (Gn 30:19-20)</span>",
    definicao: "<p><strong>Zebulom</strong> foi filho de Jacó e Lia (<span class='versiculo'>Gn 30:19-20</span>). Lia disse: 'Deus me dotou de boa dávila; agora morará comigo meu marido'.</p><ul><li><strong>Nome:</strong> significa 'habitação' ou 'dote'</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:13</span>) diz que Zebulom habitará na costa do mar</li><li>A tribo de Zebulom era guerreira (<span class='versiculo'>Jz 5:18</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:19-20; Gn 35:23; Gn 46:14; Gn 49:13; Êx 1:3; Nm 1:30-31; Dt 33:18-19; Js 19:10-16; Jz 5:18; Mt 4:13-16</span>"
},
{
    termo: "<span class='numero-ordem'>753.</span> <span class='nome-principal'>Dã</span> <span class='subtitulo'>– quinto filho de Jacó, primeiro de Bila (serva de Raquel) (Gn 30:5-6)</span>",
    definicao: "<p><strong>Dã</strong> foi filho de Jacó com Bila, serva de Raquel (<span class='versiculo'>Gn 30:5-6</span>). Raquel disse: 'Deus me fez justiça'.</p><ul><li><strong>Nome:</strong> significa 'julgou' ou 'juiz'</li><li>A tribo de Dã foi a que se estabeleceu no norte</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:16-17</span>) diz que Dã julgará seu povo, mas será serpente</li><li>Sansão era da tribo de Dã (<span class='versiculo'>Jz 13:2</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:5-6; Gn 35:25; Gn 46:23; Gn 49:16-17; Êx 1:4; Nm 1:38-39; Js 19:40-48; Jz 13:2; Jz 18; Ap 7:5-8</span>"
},
{
    termo: "<span class='numero-ordem'>754.</span> <span class='nome-principal'>Naftali</span> <span class='subtitulo'>– sexto filho de Jacó, segundo de Bila (serva de Raquel) (Gn 30:7-8)</span>",
    definicao: "<p><strong>Naftali</strong> foi filho de Jacó com Bila (<span class='versiculo'>Gn 30:7-8</span>). Raquel disse: 'Lutas de Deus lutei com minha irmã e venci'.</p><ul><li><strong>Nome:</strong> significa 'minha luta' ou 'astúcia'</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:21</span>) diz: 'Naftali é uma gazela solta'</li><li>A tribo de Naftali recebeu terra na Galileia (<span class='versiculo'>Js 19:32-39</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:7-8; Gn 35:25; Gn 46:24; Gn 49:21; Êx 1:4; Nm 1:42-43; Dt 33:23; Js 19:32-39; Jz 4:6; Mt 4:13-16</span>"
},
{
    termo: "<span class='numero-ordem'>755.</span> <span class='nome-principal'>Gade</span> <span class='subtitulo'>– sétimo filho de Jacó, primeiro de Zilpa (serva de Lia) (Gn 30:10-11)</span>",
    definicao: "<p><strong>Gade</strong> foi filho de Jacó com Zilpa (<span class='versiculo'>Gn 30:10-11</span>). Lia disse: 'Que boa sorte!'.</p><ul><li><strong>Nome:</strong> significa 'sorte' ou 'bando'</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:19</span>) diz: 'Gade será atacado por uma tropa, mas ele a atacará'</li><li>A tribo de Gade recebeu terra a leste do Jordão (<span class='versiculo'>Nm 32</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:10-11; Gn 35:26; Gn 46:16; Gn 49:19; Nm 1:24-25; Nm 32; Dt 33:20-21; Js 13:24-28; 1Cr 5:11-26; Ap 7:5</span>"
},
{
    termo: "<span class='numero-ordem'>756.</span> <span class='nome-principal'>Aser</span> <span class='subtitulo'>– oitavo filho de Jacó, segundo de Zilpa (serva de Lia) (Gn 30:12-13)</span>",
    definicao: "<p><strong>Aser</strong> foi filho de Jacó com Zilpa (<span class='versiculo'>Gn 30:12-13</span>). Lia disse: 'Para minha felicidade! As mulheres me chamarão feliz'.</p><ul><li><strong>Nome:</strong> significa 'feliz' ou 'bem-aventurado'</li><li>A bênção de Jacó (<span class='versiculo'>Gn 49:20</span>) diz: 'De Aser, o seu pão será gordo'</li><li>A profetisa Ana era da tribo de Aser (<span class='versiculo'>Lc 2:36</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 30:12-13; Gn 35:26; Gn 46:17; Gn 49:20; Nm 1:40-41; Dt 33:24-25; Js 19:24-31; Lc 2:36; Ap 7:6</span>"
},
{
    termo: "<span class='numero-ordem'>757.</span> <span class='nome-principal'>Serrá (filha de Aser)</span> <span class='subtitulo'>– mencionada em Números 26:46</span>",
    definicao: "<p><strong>Serrá</strong> (ou Sera) é uma filha de Aser, mencionada na lista genealógica em <span class='versiculo'>Nm 26:46</span> (e <span class='versiculo'>1Cr 7:30</span>).</p><ul><li><strong>Nome:</strong> significa 'princesa' ou 'parente'</li><li>Serrá é exemplo de que as mulheres também eram registradas</li><li>É um dos personagens mais obscuros, mas seu nome está nas Escrituras</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 26:46; 1Cr 7:30</span>"
},
{
    termo: "<span class='numero-ordem'>758.</span> <span class='nome-principal'>Adna, Jozabade, e outros</span> <span class='subtitulo'>– guerreiros de Davi da tribo de Manassés (1Cr 12:20-21)</span>",
    definicao: "<p>Em <span class='versiculo'>1Cr 12:20-21</span>, vários guerreiros de Manassés se uniram a Davi em Ziclague. <strong>Adna, Jozabade, Jediael, Micael, Jozabade, Eliú, Ziletai</strong> são nomes.</p><ul><li>São descritos como 'capitães de milhares' e 'valentes'</li><li>Representam os muitos guerreiros anônimos que apoiaram Davi</li><li>Adna significa 'prazer' ou 'delícia'; Jozabade 'Yahweh dotou'</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 12:20-21</span>"
},
{
    termo: "<span class='numero-ordem'>759.</span> <span class='nome-principal'>Obede-Edom</span> <span class='subtitulo'>– geteu que guardou a Arca, abençoado por Deus (2Sm 6:10-12)</span>",
    definicao: "<p><strong>Obede-Edom</strong> era natural de Gate ou levita. Quando Davi tentou trazer a Arca e Uzá morreu, a Arca ficou na casa de Obede-Edom por três meses. <span class='destaque-amarelo'>Deus o abençoou grandemente</span> (<span class='versiculo'>2Sm 6:10-12</span>; <span class='versiculo'>1Cr 13:13-14</span>).</p><ul><li><strong>Nome:</strong> significa 'servo de Edom'</li><li>Obede-Edom é exemplo de hospitalidade e bênção</li><li>Deus o abençoou com oito filhos (<span class='versiculo'>1Cr 26:5</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 6:10-12; 1Cr 13:13-14; 1Cr 15:18-25; 1Cr 16:5,38; 1Cr 26:4-8,15</span>"
},
{
    termo: "<span class='numero-ordem'>760.</span> <span class='nome-principal'>Merabe</span> <span class='subtitulo'>– filha mais velha de Saul, prometida a Davi (1Sm 18:17-19)</span>",
    definicao: "<p><strong>Merabe</strong> era filha mais velha de Saul (<span class='versiculo'>1Sm 14:49</span>). Saul prometeu dar Merabe a Davi como esposa, mas depois a deu a Adriel (<span class='versiculo'>1Sm 18:17-19</span>).</p><ul><li><strong>Nome:</strong> significa 'aumento' ou 'grandeza'</li><li>Merabe é exemplo de promessa não cumprida e tragédia familiar</li><li>Teve cinco filhos com Adriel, que foram executados pelos gibeonitas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 14:49; 1Sm 18:17-19; 2Sm 21:8</span>"
},
{
    termo: "<span class='numero-ordem'>761.</span> <span class='nome-principal'>Adriel, o meolatita</span> <span class='subtitulo'>– genro de Saul, casado com Merabe (2Sm 21:8)</span>",
    definicao: "<p><strong>Adriel</strong> era filho de Barzilai (não o gileadita). Casou-se com Merabe, filha de Saul. Teve cinco filhos com ela, que foram executados pelos gibeonitas (<span class='versiculo'>2Sm 21:8</span>).</p><ul><li><strong>Nome:</strong> significa 'ajuda de Deus'</li><li>Adriel é exemplo de aliança política e tragédia</li><li>É mencionado apenas em <span class='versiculo'>1Sm 18:19</span> e <span class='versiculo'>2Sm 21:8</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 18:19; 2Sm 21:8</span>"
},
{
    termo: "<span class='numero-ordem'>762.</span> <span class='nome-principal'>Rizpa</span> <span class='subtitulo'>– concubina de Saul, mãe de Armoni e Mefibosete (2Sm 21:8-11)</span>",
    definicao: "<p><strong>Rizpa</strong> era concubina do rei Saul, mãe de Armoni e Mefibosete. Após a morte de Saul, os gibeonitas pediram a execução de sete descendentes de Saul. Rizpa <span class='destaque-amarelo'>protegeu os corpos de seus filhos mortos</span>, espalhando pano de saco sobre uma rocha e afugentando aves e animais por dias, até que Davi ordenou o sepultamento (<span class='versiculo'>2Sm 21:8-11</span>).</p><ul><li><strong>Nome:</strong> significa 'brasa' ou 'pedra quente'</li><li>Rizpa é exemplo de amor materno e protesto silencioso</li><li>É uma das heroínas trágicas do AT</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 3:7; 2Sm 21:8-11</span>"
},
{
    termo: "<span class='numero-ordem'>763.</span> <span class='nome-principal'>Armoni e Mefibosete (filhos de Saul)</span> <span class='subtitulo'>– executados pelos gibeonitas (2Sm 21:8-14)</span>",
    definicao: "<p><strong>Armoni e Mefibosete</strong> eram filhos de Saul com Rizpa (<span class='versiculo'>2Sm 21:8</span>). Foram entregues aos gibeonitas para serem executados a fim de expiar o pecado de Saul contra eles (<span class='versiculo'>2Sm 21:1-6</span>).</p><ul><li>Armoni ('príncipe'); Mefibosete (aqui é outro, não o filho de Jônatas)</li><li>São exemplos de sofrimento por causa do pecado de antepassados</li><li>Rizpa os protegeu após a morte</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 21:8-14</span>"
},
{
    termo: "<span class='numero-ordem'>764.</span> <span class='nome-principal'>Simeão (ancião)</span> <span class='subtitulo'>– homem justo que viu o Cristo no templo (Lc 2:25-35)</span>",
    definicao: "<p><strong>Simeão</strong> era um homem justo e piedoso em Jerusalém, que aguardava a consolação de Israel. O Espírito Santo lhe revelou que não morreria antes de ver o Cristo. Quando Maria e José apresentaram Jesus no templo, Simeão o tomou nos braços e disse o <span class='destaque-amarelo'>Nunc Dimittis</span> (<span class='versiculo'>Lc 2:25-35</span>).</p><ul><li><strong>Nome:</strong> significa 'ouvir' (mesmo de Simão)</li><li>Simeão é exemplo de fidelidade e espera</li><li>Sua canção (Nunc Dimittis) é usada nas liturgias</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 2:25-35</span>"
},
{
    termo: "<span class='numero-ordem'>765.</span> <span class='nome-principal'>Ana (profetisa)</span> <span class='subtitulo'>– filha de Fanuel, da tribo de Aser, que viu Jesus no templo (Lc 2:36-38)</span>",
    definicao: "<p><strong>Ana</strong> era profetisa idosa (84 anos), que vivia no templo, servindo a Deus em jejuns e orações. Após a apresentação de Jesus por Simeão, Ana também deu graças a Deus e falou a respeito do menino a todos que esperavam a redenção (<span class='versiculo'>Lc 2:36-38</span>).</p><ul><li><strong>Nome:</strong> significa 'graça'</li><li>Ana é exemplo de devoção e testemunha</li><li>Ela reconheceu Jesus como o Messias</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 2:36-38</span>"
},
{
    termo: "<span class='numero-ordem'>766.</span> <span class='nome-principal'>Clopas</span> <span class='subtitulo'>– marido de Maria, que estava na cruz (Jo 19:25)</span>",
    definicao: "<p><strong>Clopas</strong> é mencionado apenas em <span class='versiculo'>Jo 19:25</span>: 'Maria, mulher de Clopas'. Ele é o marido de uma das Marias que estava na cruz.</p><ul><li><strong>Nome:</strong> significa 'troca' ou 'celeiro'</li><li>Clopas é uma figura obscura</li><li>Alguns o identificam com Cleopas de Emaús (<span class='versiculo'>Lc 24:18</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 19:25; Lc 24:18</span>"
},
{
    termo: "<span class='numero-ordem'>767.</span> <span class='nome-principal'>Bitiá</span> <span class='subtitulo'>– filha de Faraó que casou com Merede (1Cr 4:18)</span>",
    definicao: "<p><strong>Bitiá</strong> (ou Bítia) é mencionada em <span class='versiculo'>1Cr 4:18</span> como 'Bitiá, filha de Faraó, que Merede tomou por mulher'. É uma princesa egípcia que se casou com um israelita.</p><ul><li><strong>Nome:</strong> significa 'filha de Yahweh' ou 'filha do deus Rá'</li><li>Bitiá representa a integração de estrangeiros no povo de Deus</li><li>A tradição a identifica com a filha de Faraó que criou Moisés (<span class='versiculo'>Êx 2:5-10</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 4:18</span>"
},
{
    termo: "<span class='numero-ordem'>768.</span> <span class='nome-principal'>Manoá</span> <span class='subtitulo'>– pai de Sansão (Jz 13:2-25)</span>",
    definicao: "<p><strong>Manoá</strong>, da tribo de Dã, foi pai de Sansão. Ele e sua esposa eram estéreis. O anjo do Senhor apareceu à mulher e anunciou que ela daria à luz um nazireu. Manoá orou pedindo uma visita do anjo. O anjo apareceu novamente e deu instruções. Manoá exclamou: <span class='destaque-amarelo'>'Morreremos, porque vimos a Deus!'</span> (<span class='versiculo'>Jz 13:22</span>).</p><ul><li><strong>Nome:</strong> significa 'descanso'</li><li>Manoá é exemplo de fé e temor</li><li>Ele criou Sansão segundo as instruções divinas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 13:2-25; Jz 16:31</span>"
},
{
    termo: "<span class='numero-ordem'>769.</span> <span class='nome-principal'>A esposa de Manoá</span> <span class='subtitulo'>– mãe de Sansão, estéril que recebeu o anjo (Jz 13:2-25)</span>",
    definicao: "<p>A <strong>esposa de Manoá</strong> (anônima) era estéril. O anjo do Senhor apareceu a ela e anunciou que daria à luz um filho nazireu (<span class='versiculo'>Jz 13:2-5</span>).</p><ul><li>Ela é exemplo de humildade e obediência</li><li>Reconheceu a visão como divina</li><li>A tradição a chama de <strong>Hazelelponi</strong> (nome apócrifo)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 13:2-25</span>"
},
{
    termo: "<span class='numero-ordem'>770.</span> <span class='nome-principal'>Seraías</span> <span class='subtitulo'>– escriba de Davi, filho de Azarias (2Sm 8:17)</span>",
    definicao: "<p><strong>Seraías</strong> foi escriba (secretário) do rei Davi, mencionado em <span class='versiculo'>2Sm 8:17</span> e <span class='versiculo'>2Sm 20:25</span>. Era responsável pelos registros oficiais do reino.</p><ul><li><strong>Nome:</strong> significa 'Yahweh é príncipe'</li><li>Seraías representa os muitos servidores públicos que trabalharam nos bastidores</li><li>Em <span class='versiculo'>1Cr 18:16</span>, o nome aparece como Sausá (variação)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 8:17; 2Sm 20:25; 1Cr 18:16</span>"
},
{
    termo: "<span class='numero-ordem'>771.</span> <span class='nome-principal'>Jeter (Itra, o ismaelita)</span> <span class='subtitulo'>– pai de Amasa, genro de Davi (2Sm 17:25; 1Cr 2:17)</span>",
    definicao: "<p><strong>Jeter</strong> (ou Itra) era pai de Amasa. Jeter era ismaelita (<span class='versiculo'>1Cr 2:17</span>) ou israelita (<span class='versiculo'>2Sm 17:25</span>). Casou-se com Abigail, irmã de Davi.</p><ul><li><strong>Nome:</strong> significa 'sobra' ou 'abundância'</li><li>Jeter é exemplo de aliança familiar com a casa real</li><li>É uma figura obscura, mas sua linhagem conectou-se à casa de Davi</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 17:25; 1Cr 2:17</span>"
},
{
    termo: "<span class='numero-ordem'>772.</span> <span class='nome-principal'>Hodes</span> <span class='subtitulo'>– mulher de Gade, mencionada em 1Crônicas 7:13</span>",
    definicao: "<p><strong>Hodes</strong> é mencionada em <span class='versiculo'>1Cr 7:13</span> como esposa de Gade, o sétimo filho de Jacó. Foi mãe de sete filhos.</p><ul><li><strong>Nome:</strong> significa 'lua nova' (hebraico)</li><li>Hodes representa as mulheres anônimas que deram continuidade às tribos</li><li>É uma figura de transição</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Cr 7:13</span>"
},
{
    termo: "<span class='numero-ordem'>773.</span> <span class='nome-principal'>Izehar (Izhar)</span> <span class='subtitulo'>– pai de Corá, levita da família de Coate (Êx 6:18; Nm 3:19)</span>",
    definicao: "<p><strong>Izehar</strong> era filho de Coate, neto de Levi, tio de Moisés e Arão (<span class='versiculo'>Êx 6:18</span>; <span class='versiculo'>Nm 3:19</span>). Foi pai de Corá (o líder da rebelião).</p><ul><li><strong>Nome:</strong> significa 'óleo ungido' ou 'brilho'</li><li>Izehar é exemplo de levita cujo filho se rebelou</li><li>Apesar de Corá ter sido punido, os descendentes de Izehar continuaram servindo (<span class='versiculo'>1Cr 26:23,29</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 6:18; Nm 3:19; Nm 16:1; 1Cr 6:2,18; 1Cr 26:23,29</span>"
},
{
    termo: "<span class='numero-ordem'>774.</span> <span class='nome-principal'>Elisama, filho de Amiúde</span> <span class='subtitulo'>– príncipe da tribo de Efraim, líder do censo (Nm 1:10; 2:18)</span>",
    definicao: "<p><strong>Elisama</strong> foi líder da tribo de Efraim durante o censo no deserto (<span class='versiculo'>Nm 1:10</span>; <span class='versiculo'>2:18</span>). Era pai de Num, avô de Josué (<span class='versiculo'>1Cr 7:26-27</span>).</p><ul><li><strong>Nome:</strong> significa 'meu Deus ouviu'</li><li>Elisama é exemplo de liderança tribal fiel</li><li>Morreu no deserto, mas seu neto Josué entrou em Canaã</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 1:10; Nm 2:18; Nm 7:48-53; 1Cr 7:26-27</span>"
},
{
    termo: "<span class='numero-ordem'>775.</span> <span class='nome-principal'>Gamaliel, filho de Pedazur</span> <span class='subtitulo'>– príncipe da tribo de Manassés (Nm 1:10; 2:20)</span>",
    definicao: "<p><strong>Gamaliel</strong> foi líder da tribo de Manassés durante o censo (<span class='versiculo'>Nm 1:10</span>; <span class='versiculo'>2:20</span>). Ofereceu a oferta de dedicação do altar (<span class='versiculo'>Nm 7:54-59</span>).</p><ul><li><strong>Nome:</strong> significa 'recompensa de Deus'</li><li>Não confundir com Gamaliel, o fariseu</li><li>Gamaliel é uma figura obscura, mas fiel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 1:10; Nm 2:20; Nm 7:54-59</span>"
},
{
    termo: "<span class='numero-ordem'>776.</span> <span class='nome-principal'>Abidã, filho de Gideoni</span> <span class='subtitulo'>– príncipe da tribo de Benjamim (Nm 1:11; 2:22)</span>",
    definicao: "<p><strong>Abidã</strong> foi líder da tribo de Benjamim no censo do deserto (<span class='versiculo'>Nm 1:11</span>; <span class='versiculo'>2:22</span>). Ofereceu a oferta de dedicação do altar (<span class='versiculo'>Nm 7:60-65</span>).</p><ul><li><strong>Nome:</strong> significa 'meu pai julgou'</li><li>Abidã morreu no deserto</li><li>Representa os líderes que ajudaram a organizar o povo de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 1:11; Nm 2:22; Nm 7:60-65</span>"
},
{
    termo: "<span class='numero-ordem'>777.</span> <span class='nome-principal'>Aías, o silonita</span> <span class='subtitulo'>– profeta que anunciou a divisão do reino a Jeroboão (1Rs 11:29-39)</span>",
    definicao: "<p><strong>Aías</strong> foi profeta de Siló (<span class='versiculo'>1Rs 11:29-39</span>). Foi enviado por Deus a Jeroboão para anunciar que ele reinaria sobre dez tribos, rasgando sua capa em doze pedaços. Também profetizou a morte do filho de Jeroboão, Abias (<span class='versiculo'>1Rs 14:1-18</span>).</p><ul><li><strong>Nome:</strong> significa 'irmão de Yahweh'</li><li>Aías é exemplo de profeta corajoso que anuncia juízo</li><li>Aías ficou cego na velhice, mas reconheceu a esposa de Jeroboão disfarçada</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 11:29-39; 1Rs 14:1-18</span>"
},
{
    termo: "<span class='numero-ordem'>778.</span> <span class='nome-principal'>Semaías (profeta de Roboão)</span> <span class='subtitulo'>– o que proibiu a guerra contra as dez tribos (1Rs 12:22-24)</span>",
    definicao: "<p><strong>Semaías</strong> foi profeta no reinado de Roboão (<span class='versiculo'>1Rs 12:22-24</span>; <span class='versiculo'>2Cr 11:2-4</span>). Quando Roboão se preparava para guerrear contra as tribos rebeladas, Semaías disse: <span class='destaque-amarelo'>'Isto vem de mim, diz o Senhor'</span>.</p><ul><li><strong>Nome:</strong> significa 'Yahweh ouviu'</li><li>Semaías é exemplo de profeta que orienta o rei a aceitar a vontade divina</li><li>Ele escreveu crônicas de Roboão (<span class='versiculo'>2Cr 12:15</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 12:22-24; 2Cr 11:2-4; 2Cr 12:5-8,15</span>"
},
{
    termo: "<span class='numero-ordem'>779.</span> <span class='nome-principal'>Hanani, o vidente</span> <span class='subtitulo'>– pai do profeta Jeú, que confrontou Asa (2Cr 16:7-10)</span>",
    definicao: "<p><strong>Hanani</strong> foi vidente nos dias de Asa, rei de Judá. Confrontou o rei Asa por ter confiado na Síria em vez de no Senhor (<span class='versiculo'>2Cr 16:7-10</span>). Asa o prendeu na prisão por causa disso.</p><ul><li><strong>Nome:</strong> significa 'gracioso'</li><li>Hanani é pai de Jeú (profeta contra Baasa)</li><li>Representa os profetas que sofrem perseguição por falar a verdade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Cr 16:7-10; 1Rs 16:1</span>"
},
{
    termo: "<span class='numero-ordem'>780.</span> <span class='nome-principal'>Jeú, filho de Hanani</span> <span class='subtitulo'>– profeta que anunciou juízo contra Baasa e Josafá (1Rs 16:1-7; 2Cr 19:2-3)</span>",
    definicao: "<p><strong>Jeú</strong>, filho de Hanani, foi profeta (<span class='versiculo'>1Rs 16:1-7</span>; <span class='versiculo'>2Cr 19:2-3</span>). Anunciou a destruição da casa de Baasa e confrontou o rei Josafá por sua aliança com Acabe: <span class='destaque-amarelo'>'Devias tu ajudar ao ímpio e amar aqueles que odeiam ao Senhor?'</span> (<span class='versiculo'>2Cr 19:2</span>).</p><ul><li><strong>Nome:</strong> significa 'Yahweh é ele'</li><li>Jeú é exemplo de profeta que não teme confrontar reis</li><li>Ele escreveu crônicas de Josafá (<span class='versiculo'>2Cr 20:34</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 16:1-7; 2Cr 19:2-3; 2Cr 20:34</span>"
},
{
    termo: "<span class='numero-ordem'>781.</span> <span class='nome-principal'>Micaías, filho de Inlá</span> <span class='subtitulo'>– profeta que profetizou a morte de Acabe (1Rs 22:1-28)</span>",
    definicao: "<p><strong>Micaías</strong> foi profeta em Israel, conhecido por sua confrontação com o rei Acabe (<span class='versiculo'>1Rs 22:1-28</span>). Acabe o odiava porque ele sempre profetizava o mal. Micaías profetizou a derrota e a morte de Acabe. Foi preso. Sua profecia se cumpriu.</p><ul><li><strong>Nome:</strong> significa 'quem é como Yahweh?'</li><li>Micaías representa a minoria profética que se mantém fiel</li><li>Sua prisão não o fez calar</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 22:1-28; 2Cr 18:1-27</span>"
},
{
    termo: "<span class='numero-ordem'>782.</span> <span class='nome-principal'>Zedequias, filho de Canaana</span> <span class='subtitulo'>– falso profeta que enganou Acabe (1Rs 22:11-12)</span>",
    definicao: "<p><strong>Zedequias</strong> foi um falso profeta no reinado de Acabe, líder de um grupo de 400 profetas (<span class='versiculo'>1Rs 22:11-12</span>; <span class='versiculo'>2Cr 18:10-11</span>). Fez chifres de ferro e disse: 'Com estes ferirás os sírios'.</p><ul><li><strong>Nome:</strong> significa 'justiça de Yahweh' (ironicamente)</li><li>Zedequias representa o perigo do profetismo que agrada aos poderosos</li><li>É um personagem trágico</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 22:11-25; 2Cr 18:10-23</span>"
},
{
    termo: "<span class='numero-ordem'>783.</span> <span class='nome-principal'>Susana</span> <span class='subtitulo'>– discípula que servia a Jesus com seus bens (Lc 8:3)</span>",
    definicao: "<p><strong>Susana</strong> é uma das mulheres que acompanhavam Jesus e os doze, mencionada em <span class='versiculo'>Lc 8:3</span> como alguém que servia a Jesus com seus bens.</p><ul><li><strong>Nome:</strong> significa 'lírio' (hebraico)</li><li>Susana representa as muitas mulheres anônimas que contribuíram para o sustento de Jesus</li><li>No NT, apenas em Lucas 8</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 8:1-3</span>"
},
{
    termo: "<span class='numero-ordem'>784.</span> <span class='nome-principal'>Joana, mulher de Cuza</span> <span class='subtitulo'>– discípula, testemunha da ressurreição (Lc 8:3; 24:10)</span>",
    definicao: "<p><strong>Joana</strong> era esposa de Cuza, procurador de Herodes Antipas (<span class='versiculo'>Lc 8:3</span>). Era uma mulher de posição social elevada. Servia a Jesus com seus bens. Esteve presente no sepultamento e foi ao túmulo na manhã da ressurreição (<span class='versiculo'>Lc 24:10</span>).</p><ul><li><strong>Nome:</strong> significa 'Yahweh é gracioso'</li><li>Joana é exemplo de discípula fiel e testemunha da ressurreição</li><li>É uma das primeiras a anunciar a ressurreição</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 8:3; Lc 24:10</span>"
},
{
    termo: "<span class='numero-ordem'>785.</span> <span class='nome-principal'>Cuza</span> <span class='subtitulo'>– procurador de Herodes Antipas, marido de Joana (Lc 8:3)</span>",
    definicao: "<p><strong>Cuza</strong> era administrador (procurador) da casa de Herodes Antipas. Sua esposa, Joana, era seguidora de Jesus (<span class='versiculo'>Lc 8:3</span>).</p><ul><li><strong>Nome:</strong> significa 'pequena garrafa' ou 'vaso'</li><li>Cuza é exemplo de esposo que não impedia o serviço religioso de sua mulher</li><li>Não se sabe se Cuza se converteu</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 8:3</span>"
},
{
    termo: "<span class='numero-ordem'>786.</span> <span class='nome-principal'>Cléopas (Cleopas)</span> <span class='subtitulo'>– discípulo de Emaús, testemunha da ressurreição (Lc 24:13-35)</span>",
    definicao: "<p><strong>Cléopas</strong> foi um dos dois discípulos que caminhavam para Emaús no dia da ressurreição (<span class='versiculo'>Lc 24:13-35</span>). Jesus se juntou a eles, mas não o reconheceram. Ao partirem o pão, reconheceram Jesus.</p><ul><li><strong>Nome:</strong> significa 'glória do pai'</li><li>Cléopas representa os discípulos que, mesmo tristes, encontram Cristo no caminho</li><li>A tradição diz que Cléopas tornou-se bispo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 24:13-35; Jo 19:25 (possível identificação)</span>"
},
{
    termo: "<span class='numero-ordem'>787.</span> <span class='nome-principal'>O paralítico de Cafarnaum</span> <span class='subtitulo'>– carregado por quatro amigos (Mc 2:1-12)</span>",
    definicao: "<p>O <strong>paralítico de Cafarnaum</strong> foi levado por quatro amigos a Jesus (<span class='versiculo'>Mc 2:1-12</span>). Como não podiam entrar, abriram o telhado. Jesus, vendo a fé deles, disse: <span class='destaque-amarelo'>'Filho, os teus pecados estão perdoados'</span>.</p><ul><li>Ele se levantou, tomou sua cama e saiu</li><li>É exemplo de fé cooperativa e do perdão divino</li><li>O milagre demonstra a conexão entre perdão e cura</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 2:1-12; Mt 9:1-8; Lc 5:17-26</span>"
},
{
    termo: "<span class='numero-ordem'>788.</span> <span class='nome-principal'>O homem da mão atrofiada</span> <span class='subtitulo'>– curado por Jesus no sábado (Mt 12:9-14)</span>",
    definicao: "<p>O <strong>homem da mão atrofiada</strong> foi curado por Jesus na sinagoga, em dia de sábado (<span class='versiculo'>Mt 12:9-14</span>), provocando a ira dos fariseus. Jesus perguntou: <span class='destaque-amarelo'>'É lícito no sábado fazer o bem?'</span> e ordenou ao homem que estendesse a mão; ela foi curada.</p><ul><li>Os fariseus conspiraram para matar Jesus</li><li>Representa a cura que desafia o legalismo</li><li>Sua obediência ('estendeu a mão') foi ato de fé</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 12:9-14; Mc 3:1-6; Lc 6:6-11</span>"
},
{
    termo: "<span class='numero-ordem'>789.</span> <span class='nome-principal'>O endemoninhado geraseno (Legião)</span> <span class='subtitulo'>– homem possuído por muitos demônios (Mc 5:1-20)</span>",
    definicao: "<p>O <strong>endemoninhado geraseno</strong> era um homem da região de Gerasa, possesso por uma legião de demônios (<span class='versiculo'>Mc 5:1-20</span>). Jesus ordenou que os demônios saíssem; eles entraram em uma manada de porcos, que se afogou. O homem foi curado e passou a anunciar o que Jesus lhe fizera.</p><ul><li>É exemplo de libertação poderosa e testemunho missionário</li><li>O homem queria seguir Jesus, mas foi enviado para testemunhar em sua própria região</li><li>Representa a restauração total: juízo, liberdade e propósito</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 5:1-20; Mt 8:28-34; Lc 8:26-39</span>"
},
{
    termo: "<span class='numero-ordem'>790.</span> <span class='nome-principal'>O surdo-mudo da região de Decápolis</span> <span class='subtitulo'>– curado por Jesus com toque (Mc 7:31-37)</span>",
    definicao: "<p>O <strong>surdo-mudo da região de Decápolis</strong> era surdo e com dificuldade de falar. Jesus o tirou da multidão, tocou-lhe os ouvidos e a língua, suspirou e disse: <span class='destaque-amarelo'>'Efatá!'</span> (Abre-te). Imediatamente ele ouviu e falou claramente (<span class='versiculo'>Mc 7:31-37</span>).</p><ul><li>Este milagre é exclusivo de Marcos</li><li>Jesus o levou à parte, mostrando discrição</li><li>Representa aqueles que precisam de um encontro pessoal com Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 7:31-37</span>"
},
{
    termo: "<span class='numero-ordem'>791.</span> <span class='nome-principal'>O cego de Betsaida</span> <span class='subtitulo'>– curado em dois estágios (Mc 8:22-26)</span>",
    definicao: "<p>O <strong>cego de Betsaida</strong> foi trazido a Jesus. Jesus o levou para fora da aldeia, colocou saliva nos olhos, impôs as mãos e perguntou: 'Vês alguma coisa?'. Ele respondeu: 'Vejo os homens como árvores que andam'. Jesus tocou novamente seus olhos, e ele viu claramente (<span class='versiculo'>Mc 8:22-26</span>).</p><ul><li>Este é o único milagre de cura progressiva</li><li>Simboliza a progressão da fé dos discípulos</li><li>O cego representa todo discípulo que precisa de um segundo toque</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mc 8:22-26</span>"
},
{
    termo: "<span class='numero-ordem'>792.</span> <span class='nome-principal'>A mulher encurvada</span> <span class='subtitulo'>– curada por Jesus no sábado (Lc 13:10-17)</span>",
    definicao: "<p>A <strong>mulher encurvada</strong> estava encurvada, incapaz de se endireitar, há dezoito anos, por causa de um espírito de enfermidade. Jesus a chamou e disse: <span class='destaque-amarelo'>'Mulher, estás livre da tua enfermidade'</span>. Impôs as mãos, e ela se endireitou (<span class='versiculo'>Lc 13:10-17</span>).</p><ul><li>O chefe da sinagoga se indignou por Jesus ter curado no sábado</li><li>Ela é chamada de 'filha de Abraão'</li><li>Representa todos os que estão oprimidos por Satanás e são libertos por Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 13:10-17</span>"
},
{
    termo: "<span class='numero-ordem'>793.</span> <span class='nome-principal'>O homem hidrópico</span> <span class='subtitulo'>– curado por Jesus em dia de sábado (Lc 14:1-6)</span>",
    definicao: "<p>O <strong>homem hidrópico</strong> sofria de hidropisia. Jesus estava na casa de um fariseu importante, em dia de sábado. Ele perguntou aos doutores da lei: 'É lícito curar no sábado?' Eles silenciaram. Jesus curou o homem e o despediu (<span class='versiculo'>Lc 14:1-6</span>).</p><ul><li>Este milagre é exclusivo de Lucas</li><li>Jesus usou a ocasião para ensinar sobre humildade</li><li>O homem hidrópico representa aqueles que sofrem com doenças que a religião não consegue aliviar</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 14:1-6</span>"
},
{
    termo: "<span class='numero-ordem'>794.</span> <span class='nome-principal'>O coxo de Listra</span> <span class='subtitulo'>– curado por Paulo, que confundiu os pagãos (At 14:8-10)</span>",
    definicao: "<p>O <strong>coxo de Listra</strong> era um homem aleijado de nascença, que nunca andara. Paulo o viu, percebeu que tinha fé para ser curado, e disse: <span class='destaque-amarelo'>'Levanta-te sobre os teus pés'</span>. Ele saltou e começou a andar (<span class='versiculo'>At 14:8-10</span>).</p><ul><li>As multidões, vendo o milagre, começaram a gritar que Paulo e Barnabé eram deuses</li><li>Paulo e Barnabé rasgaram suas vestes e pregaram o evangelho</li><li>É o primeiro milagre registrado de Paulo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 14:8-10</span>"
},
{
    termo: "<span class='numero-ordem'>795.</span> <span class='nome-principal'>A moça com espírito de adivinhação</span> <span class='subtitulo'>– liberta por Paulo em Filipos (At 16:16-18)</span>",
    definicao: "<p>A <strong>moça com espírito de adivinhação</strong> era uma jovem escrava que tinha um espírito de adivinhação. Seguia Paulo e Silas, gritando: <span class='destaque-amarelo'>'Estes homens são servos do Deus Altíssimo'</span> (<span class='versiculo'>At 16:16-18</span>). Paulo, perturbado, ordenou que o espírito saísse dela em nome de Jesus.</p><ul><li>Ela falava a verdade, mas o espírito era maligno</li><li>Após sua libertação, ela perdeu o dom da adivinhação</li><li>Sua história desencadeou a conversão do carcereiro</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 16:16-18</span>"
},
{
    termo: "<span class='numero-ordem'>796.</span> <span class='nome-principal'>O homem coxo do templo</span> <span class='subtitulo'>– curado por Pedro e João (At 3:1-10)</span>",
    definicao: "<p>O <strong>homem coxo do templo</strong> era coxo de nascença, com mais de 40 anos (<span class='versiculo'>At 4:22</span>), sentado diariamente na Porta Formosa. Pedro e João disseram: <span class='destaque-amarelo'>'Não tenho prata nem ouro, mas o que tenho te dou: em nome de Jesus Cristo, o Nazareno, anda'</span> (<span class='versiculo'>At 3:1-10</span>).</p><ul><li>Ele saltou, andou e entrou no templo, louvando a Deus</li><li>Este milagre resultou na pregação de Pedro e na prisão dos apóstolos</li><li>A multidão o reconheceu</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 3:1-10; At 4:22</span>"
},
{
    termo: "<span class='numero-ordem'>797.</span> <span class='nome-principal'>A mulher de Potifar</span> <span class='subtitulo'>– seduziu José, mas não foi nomeada (Gn 39:7-20)</span>",
    definicao: "<p>A <strong>mulher de Potifar</strong> era esposa de Potifar, oficial de Faraó. Tentou seduzir José repetidamente, mas ele recusou, dizendo: <span class='destaque-amarelo'>'Como cometeria eu tamanha maldade e pecaria contra Deus?'</span> (<span class='versiculo'>Gn 39:9</span>).</p><ul><li>Certo dia, ela o agarrou, e ele fugiu, deixando suas vestes</li><li>Ela então acusou falsamente José</li><li>Seu nome não é dado na Bíblia; a tradição a chama de <strong>Zuleica</strong></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 39:7-20</span>"
},
{
    termo: "<span class='numero-ordem'>798.</span> <span class='nome-principal'>A criação de Eva (Gn 2:21-23)</span> <span class='subtitulo'>– o instituição do casamento monogâmico</span>",
    definicao: "<p>Deus fez cair um sono sobre Adão, tirou uma <span class='destaque-amarelo'>costela (ou lado)</span> e formou a mulher. Eva foi apresentada a Adão, que disse: <span class='destaque-amarelo'>'Esta é osso dos meus ossos e carne da minha carne'</span> (<span class='versiculo'>Gn 2:21-25</span>).</p><ul><li>Este ato institui o casamento monogâmico</li><li>A palavra 'costela' pode ser traduzida como 'lado', indicando igualdade e parceria</li><li>Eva é a mãe de todos os viventes</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 2:21-25</span>"
},
{
    termo: "<span class='numero-ordem'>799.</span> <span class='nome-principal'>A queda de Adão e Eva (Gn 3)</span> <span class='subtitulo'>– a entrada do pecado no mundo</span>",
    definicao: "<p>A <strong>serpente enganou Eva</strong>; comeram do fruto proibido; Deus pronunciou maldições e os expulsou do Éden (<span class='versiculo'>Gn 3:1-24</span>).</p><ul><li>A <strong>semente da mulher</strong> esmagaria a cabeça da serpente (<span class='destaque-amarelo'>protoevangelho</span>, <span class='versiculo'>Gn 3:15</span>)</li><li>Evento fundamental para a doutrina do pecado original</li><li>A queda trouxe morte, sofrimento e separação de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 3:1-24</span>"
},
{
    termo: "<span class='numero-ordem'>800.</span> <span class='nome-principal'>A vitória sobre os amalequitas (Êx 17:8-16)</span> <span class='subtitulo'>– Josué liderou Israel, Moisés ergueu as mãos</span>",
    definicao: "<p>Josué liderou Israel contra Amaleque enquanto Moisés erguia as mãos com a vara de Deus. Enquanto Moisés mantinha as mãos erguidas, Israel prevalecia; quando as abaixava, Amaleque prevalecia. Arão e Hur seguraram suas mãos. Amaleque foi derrotado (<span class='versiculo'>Êx 17:8-16</span>).</p><ul><li>Deus jurou guerra a Amaleque por gerações</li><li>O altar se chamou <span class='destaque-amarelo'>'Yahweh-Nissi'</span> (o Senhor é minha bandeira)</li><li>Este evento mostra a importância da intercessão e do apoio mútuo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 17:8-16</span>"
}
]
};
